        return score

    def get_piece_type(self, piece):
        piece_mapping = {
            'P': 'pawn', 'N': 'knight', 'B': 'bishop', 'R': 'rook', 'Q': 'queen',
            'p': 'pawn', 'n': 'knight', 'b': 'bishop', 'r': 'rook', 'q': 'queen',
        }
        return piece_mapping.get(piece)

