class ChessPositionEvaluator:
    def __init__(self, position):
        self.position = position
        self.piece_values = {
            'p': 1,  # Pawn
            'n': 3,  # Knight
            'b': 3,  # Bishop
            'r': 5,  # Rook
            'q': 9,  # Queen
            'k': 0,  # King (not counted)
        }
        self.material_count = {
            'white': {'p': 0, 'n': 0, 'b': 0, 'r': 0, 'q': 0, 'k': 0},
            'black': {'p': 0, 'n': 0, 'b': 0, 'r': 0, 'q': 0, 'k': 0},
        }

    def evaluate_position(self):
        for row in self.position:
            for piece in row:
                if piece.islower():
                    self.material_count['black'][piece] += 1
                elif piece.isupper():
                    self.material_count['white'][piece.lower()] += 1

        score = self.calculate_material_score()
        return score

    def calculate_material_score(self):
        score = 0
        for color in self.material_count:
            for piece, count in self.material_count[color].items():
                score += count * self.piece_values[piece]
        return score

    def output_evaluation(self):
        score = self.evaluate_position()
        print(f"Position Evaluation Score: {score}")

